DROP TABLE IF EXISTS `hitmusical`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `hitmusical` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `station` varchar(50) NOT NULL,
  `played_time` date NOT NULL,
  `artists_id` bigint NOT NULL,
  `songs_id` bigint NOT NULL,
  PRIMARY KEY (`id`),
  KEY `HITMUSICAL_ARTISTA_FK` (`artists_id`),
  KEY `HITMUSICAL_MUSICA_FK` (`songs_id`),
  CONSTRAINT `HITMUSICAL_ARTISTA_FK` FOREIGN KEY (`artists_id`) REFERENCES `artista` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `HITMUSICAL_MUSICA_FK` FOREIGN KEY (`songs_id`) REFERENCES `musica` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE=InnoDB AUTO_INCREMENT=800000 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
